# Blender cinematic import template generated by modele_vega_PID_ok.m
import bpy
import csv
from math import radians
from mathutils import Vector

csv_path = bpy.path.abspath("//modele_vega_PID_ok_blender.csv")
launcher_name = "VegaLauncher"
satellite_name = "DeployedSatellite"
camera_name = "VegaCamera"
flame_name = "VegaFlame"
scene_scale = 0.001
earth_radius = 6.0
earth_location = Vector((0.0, 0.0, -earth_radius - 0.3))
camera_offset = Vector((-22.0, -14.0, 10.0))
trajectory_collection_name = "VegaTrajectories"

scene = bpy.context.scene
scene.render.fps = 18
scene.render.engine = "BLENDER_EEVEE_NEXT"

launcher = bpy.data.objects.get(launcher_name)
satellite = bpy.data.objects.get(satellite_name)
camera = bpy.data.objects.get(camera_name)
flame = bpy.data.objects.get(flame_name)
if launcher is None or satellite is None:
    raise RuntimeError("Create Blender objects named VegaLauncher and DeployedSatellite before running this script.")

launcher.rotation_mode = "XYZ"
satellite.rotation_mode = "XYZ"
if camera is not None:
    camera.rotation_mode = "XYZ"
if flame is not None:
    flame.rotation_mode = "XYZ"

def ensure_collection(name):
    collection = bpy.data.collections.get(name)
    if collection is None:
        collection = bpy.data.collections.new(name)
        bpy.context.scene.collection.children.link(collection)
    return collection

def clear_object(name):
    obj = bpy.data.objects.get(name)
    if obj is not None:
        bpy.data.objects.remove(obj, do_unlink=True)

def get_or_create_material(name, base_color, emission_strength=0.0):
    mat = bpy.data.materials.get(name)
    if mat is None:
        mat = bpy.data.materials.new(name=name)
    mat.use_nodes = True
    nodes = mat.node_tree.nodes
    links = mat.node_tree.links
    nodes.clear()
    out = nodes.new("ShaderNodeOutputMaterial")
    bsdf = nodes.new("ShaderNodeBsdfPrincipled")
    bsdf.inputs["Base Color"].default_value = base_color
    bsdf.inputs["Roughness"].default_value = 0.35
    if emission_strength > 0.0:
        bsdf.inputs["Emission Color"].default_value = base_color
        bsdf.inputs["Emission Strength"].default_value = emission_strength
    links.new(bsdf.outputs["BSDF"], out.inputs["Surface"])
    return mat

def ensure_world_background():
    world = scene.world
    if world is None:
        world = bpy.data.worlds.new("World")
        scene.world = world
    world.use_nodes = True
    nodes = world.node_tree.nodes
    links = world.node_tree.links
    nodes.clear()
    out = nodes.new("ShaderNodeOutputWorld")
    bg = nodes.new("ShaderNodeBackground")
    bg.inputs["Color"].default_value = (0.01, 0.015, 0.04, 1.0)
    bg.inputs["Strength"].default_value = 1.1
    links.new(bg.outputs["Background"], out.inputs["Surface"])

def ensure_earth():
    clear_object("StylizedEarth")
    bpy.ops.mesh.primitive_uv_sphere_add(radius=earth_radius, location=earth_location)
    earth = bpy.context.active_object
    earth.name = "StylizedEarth"
    earth_mat = get_or_create_material("EarthMaterial", (0.08, 0.22, 0.52, 1.0), emission_strength=0.15)
    earth.data.materials.clear()
    earth.data.materials.append(earth_mat)
    return earth

def ensure_starfield():
    collection = ensure_collection("VegaEnvironment")
    for i in range(24):
        name = f"Star_{i:02d}"
        clear_object(name)
        bpy.ops.mesh.primitive_uv_sphere_add(radius=0.03 + 0.02 * (i % 3))
        star = bpy.context.active_object
        star.name = name
        star.location = Vector(((-18 + i * 1.5), (8 - (i % 6) * 3.0), 7 + (i % 5) * 2.0))
        star.data.materials.clear()
        star.data.materials.append(get_or_create_material("StarMaterial", (1.0, 0.97, 0.92, 1.0), emission_strength=3.0))
        collection.objects.link(star)
        if star.name in bpy.context.scene.collection.objects:
            bpy.context.scene.collection.objects.unlink(star)

def create_curve_object(name, points, bevel_depth, material_name, base_color, emission_strength):
    if not points:
        return None
    clear_object(name)
    curve = bpy.data.curves.new(name=name, type="CURVE")
    curve.dimensions = "3D"
    curve.resolution_u = 2
    curve.bevel_depth = bevel_depth
    spline = curve.splines.new("POLY")
    spline.points.add(len(points) - 1)
    for i, pt in enumerate(points):
        spline.points[i].co = (pt[0], pt[1], pt[2], 1.0)
    obj = bpy.data.objects.new(name, curve)
    obj.data.materials.append(get_or_create_material(material_name, base_color, emission_strength))
    ensure_collection(trajectory_collection_name).objects.link(obj)
    return obj

ensure_world_background()
ensure_earth()
ensure_starfield()
launcher.data.materials.clear()
launcher.data.materials.append(get_or_create_material("LauncherMaterial", (0.82, 0.86, 0.92, 1.0), emission_strength=0.0))
satellite.data.materials.clear()
satellite.data.materials.append(get_or_create_material("SatelliteMaterial", (0.15, 0.85, 1.0, 1.0), emission_strength=2.5))
if flame is not None:
    flame.data.materials.clear()
    flame.data.materials.append(get_or_create_material("FlameMaterial", (1.0, 0.45, 0.08, 1.0), emission_strength=4.0))

rows = []
launcher_points = []
satellite_points = []
with open(csv_path, newline="", encoding="utf-8") as f:
    reader = csv.DictReader(f)
    for row in reader:
        rows.append(row)
        launcher_points.append((
            float(row["launcher_x_m"]) * scene_scale,
            float(row["launcher_y_m"]) * scene_scale,
            float(row["launcher_z_m"]) * scene_scale))
        if row["satellite_visible"] == "1":
            satellite_points.append((
                float(row["satellite_x_m"]) * scene_scale,
                float(row["satellite_y_m"]) * scene_scale,
                float(row["satellite_z_m"]) * scene_scale))

create_curve_object("LauncherTrajectory", launcher_points, 0.015, "LauncherTrailMaterial", (1.0, 0.35, 0.20, 1.0), 1.2)
create_curve_object("SatelliteTrajectory", satellite_points, 0.012, "SatelliteTrailMaterial", (0.20, 0.85, 1.0, 1.0), 2.0)

for row in rows:
    frame = int(row["frame_idx"]) + 1
    scene.frame_set(frame)
    launcher_loc = Vector((
        float(row["launcher_x_m"]) * scene_scale,
        float(row["launcher_y_m"]) * scene_scale,
        float(row["launcher_z_m"]) * scene_scale))
    launcher.location = launcher_loc
    launcher.rotation_euler = (
        radians(float(row["launcher_phi_deg"])),
        radians(float(row["launcher_theta_deg"])),
        radians(float(row["launcher_psi_deg"])))
    launcher.hide_viewport = row["launcher_visible"] == "0"
    launcher.hide_render = row["launcher_visible"] == "0"
    launcher.keyframe_insert(data_path="location", frame=frame)
    launcher.keyframe_insert(data_path="rotation_euler", frame=frame)
    launcher.keyframe_insert(data_path="hide_viewport", frame=frame)
    launcher.keyframe_insert(data_path="hide_render", frame=frame)

    if row["satellite_visible"] == "1":
        satellite.location = (
            float(row["satellite_x_m"]) * scene_scale,
            float(row["satellite_y_m"]) * scene_scale,
            float(row["satellite_z_m"]) * scene_scale)
    satellite.hide_viewport = row["satellite_visible"] == "0"
    satellite.hide_render = row["satellite_visible"] == "0"
    satellite.keyframe_insert(data_path="location", frame=frame)
    satellite.keyframe_insert(data_path="hide_viewport", frame=frame)
    satellite.keyframe_insert(data_path="hide_render", frame=frame)

    if flame is not None:
        flame.location = launcher_loc
        flame.rotation_euler = launcher.rotation_euler
        thrust_on = float(row["thrust_n"]) > 0.0 and row["launcher_visible"] == "1"
        flame.hide_viewport = not thrust_on
        flame.hide_render = not thrust_on
        flame.scale = (0.55, 0.55, 0.8 + 1.3 * min(float(row["thrust_n"]) / 4500000.0, 1.0))
        flame.keyframe_insert(data_path="location", frame=frame)
        flame.keyframe_insert(data_path="rotation_euler", frame=frame)
        flame.keyframe_insert(data_path="scale", frame=frame)
        flame.keyframe_insert(data_path="hide_viewport", frame=frame)
        flame.keyframe_insert(data_path="hide_render", frame=frame)

    if camera is not None:
        target = Vector(satellite.location) if row["satellite_visible"] == "1" else launcher_loc
        camera.location = target + camera_offset
        direction = target - camera.location
        camera.rotation_euler = direction.to_track_quat("-Z", "Y").to_euler()
        camera.keyframe_insert(data_path="location", frame=frame)
        camera.keyframe_insert(data_path="rotation_euler", frame=frame)

scene.frame_start = 1
scene.frame_end = 2081
print("Import Vega/Blender cinematique termine.")
